import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Difficulty {
  SMALL = 'small',   // Hardest (lots of detail)
  MEDIUM = 'medium', // Normal
  LARGE = 'large'    // Easiest (large blocks)
}

export interface ColoringPage {
  imageUrl: string;
  prompt: string;
  difficulty: Difficulty;
}

import React, { useState, useEffect, useCallback } from 'react';

interface VoiceInputProps {
  onTranscript: (text: string) => void;
  isProcessing: boolean;
}

export const VoiceInput: React.FC<VoiceInputProps> = ({ onTranscript, isProcessing }) => {
  const [isListening, setIsListening] = useState(false);
  const [recognition, setRecognition] = useState<any>(null);

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      const rec = new SpeechRecognition();
      rec.continuous = false;
      rec.interimResults = false;
      rec.lang = 'en-US';

      rec.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        onTranscript(transcript);
        setIsListening(false);
      };

      rec.onerror = () => {
        setIsListening(false);
      };

      rec.onend = () => {
        setIsListening(false);
      };

      setRecognition(rec);
    }
  }, [onTranscript]);

  const toggleListening = () => {
    if (isListening) {
      recognition?.stop();
      setIsListening(false);
    } else {
      recognition?.start();
      setIsListening(true);
    }
  };

  if (!recognition) return null;

  return (
    <button
      onClick={toggleListening}
      disabled={isProcessing}
      className={`p-4 rounded-full transition-all transform active:scale-95 ${
        isListening 
          ? 'bg-red-500 animate-pulse ring-4 ring-red-200' 
          : 'bg-indigo-500 hover:bg-indigo-600'
      } text-white shadow-lg`}
      title="Talk to ColorBuddy"
    >
      <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
      </svg>
    </button>
  );
};

import { GoogleGenAI } from "@google/genai";
import { Difficulty } from "../types";

export const generateColoringImage = async (prompt: string, difficulty: Difficulty): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // Customizing prompt based on difficulty
  // Small surfaces = many intricate details (harder for kids)
  // Large surfaces = simple, thick lines, large open areas (easier for kids)
  let detailLevel = "thick lines, simple shapes, large empty areas, easy to color, cartoon style";
  if (difficulty === Difficulty.SMALL) {
    detailLevel = "intricate details, thin lines, many small patterns, zentangle style, detailed backgrounds";
  } else if (difficulty === Difficulty.MEDIUM) {
    detailLevel = "medium line thickness, clear subjects, some background detail, fun patterns";
  }

  const enhancedPrompt = `A black and white coloring book page for a 6 year old child. 
    Subject: ${prompt}. 
    Style: purely black outlines on a pure white background, no shading, no gray colors, clean line art. 
    Complexity: ${detailLevel}. 
    High quality, fun and friendly design.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: [{ parts: [{ text: enhancedPrompt }] }],
      config: {
        imageConfig: {
          aspectRatio: "3:4" // Close to A4 aspect ratio
        }
      }
    });

    let imageUrl = '';
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        imageUrl = `data:image/png;base64,${part.inlineData.data}`;
        break;
      }
    }

    if (!imageUrl) throw new Error("No image generated");
    return imageUrl;
  } catch (error) {
    console.error("Image generation failed:", error);
    throw error;
  }
};

import React, { useState, useRef } from 'react';
