    const textToUse = finalPrompt || prompt;
    if (!textToUse.trim()) return;

    setIsGenerating(true);
    setError(null);
    try {
      const imageUrl = await generateColoringImage(textToUse, difficulty);
      setCurrentPage({ imageUrl, prompt: textToUse, difficulty });
    } catch (err) {
      setError("Oops! My magic wand is tired. Can we try again?");
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleTranscript = (text: string) => {
    setPrompt(text);
    handleGenerate(text);
  };

