            <label className="block text-2xl kids-font text-gray-700 text-center">How big are the areas to color?</label>
            <div className="grid grid-cols-3 gap-4">
              {[
                { id: Difficulty.LARGE, label: 'Big', color: 'bg-green-100 text-green-700', border: 'border-green-400', desc: 'Easy' },
                { id: Difficulty.MEDIUM, label: 'Middle', color: 'bg-yellow-100 text-yellow-700', border: 'border-yellow-400', desc: 'Normal' },
                { id: Difficulty.SMALL, label: 'Small', color: 'bg-red-100 text-red-700', border: 'border-red-400', desc: 'Hard!' },
              ].map((opt) => (
                <button
                  key={opt.id}
                  onClick={() => setDifficulty(opt.id)}
                  className={`flex flex-col items-center justify-center p-4 rounded-2xl border-4 transition-all ${
