                <span>מצייר...</span>
              </>
            ) : (
              <>
                <span>צור</span>
                <span className="text-3xl">🎨</span>
              </>
            )}
          </button>

          {error && <p className="text-red-500 text-center font-bold animate-bounce">{error}</p>}
