                <path fillRule="evenodd" d="M10.293 16.707a1 1 0 011.414 0l6-6a1 1 0 010-1.414l-6-6a1 1 0 111.414 1.414L14.586 9H3a1 1 0 110 2h11.586l-4.293 4.293a1 1 0 010 1.414z" clipRule="evenodd" />
